const BASE = "";

// ── HTTP Request ──────────────────────────────────────────────────────────────
async function req(method, path, body) {
  const opts = {
    method,
    headers: {
      "Content-Type": "application/json",
      "Cache-Control": "no-cache, no-store",
      "Pragma": "no-cache",
    },
  };
  if (body) opts.body = JSON.stringify(body);

  // Bust Spring + browser cache on every GET
  const url =
    method === "GET"
      ? `${BASE}${path}${path.includes("?") ? "&" : "?"}_t=${Date.now()}`
      : `${BASE}${path}`;

  const res = await fetch(url, opts);

  if (!res.ok) {
    const txt = await res.text().catch(() => `HTTP ${res.status}`);
    throw new Error(txt || `HTTP ${res.status}`);
  }

  const ct = res.headers.get("content-type") || "";
  if (!ct.includes("application/json")) return res.text();

  const json = await res.json();
  return unwrap(json);
}

// ── Response Unwrapper ────────────────────────────────────────────────────────
// Handles ALL response shapes from your 4 Spring services:
//   Book-Service  → { statuscode, status, message, data: [...] }
//   User-Service  → { statuscode, status, message, list: [...] }
//   Loan-Service  → { statusCode, status, message, list: [...] }  OR single loan object
//   Fine-Service  → { statusCode, status, message, data: [...] }  OR single fine object
//   Any service   → plain array [] or plain primitive
function unwrap(json) {
  if (json === null || json === undefined) return json;

  // Primitive — number, string, boolean (e.g. totalBooks count)
  if (typeof json !== "object") return json;

  // Already a plain array — return as-is
  if (Array.isArray(json)) return json;

  // Wrapped response object — extract payload
  // Check "data" first (Book-Service, Fine-Service)
  if ("data" in json && json.data !== null && json.data !== undefined) {
    return json.data;
  }

  // Check "list" (User-Service, Loan-Service)
  if ("list" in json && json.list !== null && json.list !== undefined) {
    return json.list;
  }

  // Some services wrap in other keys — handle gracefully
  if ("users"  in json && json.users  !== null) return json.users;
  if ("books"  in json && json.books  !== null) return json.books;
  if ("loans"  in json && json.loans  !== null) return json.loans;
  if ("fines"  in json && json.fines  !== null) return json.fines;
  if ("result" in json && json.result !== null) return json.result;

  // Single entity object (one book, one user, one loan, one fine)
  // e.g. { loanId: 1, title: "...", userId: 1, status: "ACTIVE" }
  return json;
}

// ── toArray ───────────────────────────────────────────────────────────────────
// CRITICAL — always returns an array regardless of what backend sends.
// Prevents "Objects are not valid as React child" error when backend
// returns a single object instead of array (e.g. user with 1 loan).
export function toArray(val) {
  if (val === null || val === undefined) return [];
  if (Array.isArray(val)) return val;
  if (typeof val === "object") return [val]; // single object → wrap in array
  return [];
}

// ── Primary Key Helpers ───────────────────────────────────────────────────────
export const bookPK = (b) => b?.id    ?? b?.bookId  ?? null;
export const userPK = (u) => u?.id    ?? u?.userId  ?? null;
export const loanPK = (l) => l?.loanId ?? l?.id     ?? null;

// ── Loan Field Normalizer ─────────────────────────────────────────────────────
// Your Loan entity uses non-standard field names:
//   borrowAt      instead of borrowedAt
//   returnredAt   instead of returnedAt  (typo in entity)
//   loanId        instead of id
export function normalizeLoan(l) {
  return {
    id:          loanPK(l),
    title:       String(l.title        ?? "—"),
    userId:      String(l.userId       ?? "—"),
    borrowedAt:  String(l.borrowAt     ?? l.borrowedAt  ?? "—"),
    dueDate:     String(l.dueDate      ?? "—"),
    returnedAt:  String(l.returnredAt  ?? l.returnedAt  ?? "—"),
    totalAmount: l.totalAmount         ?? null,
    status:      String(l.status       ?? "—"),
  };
}

// ── API Calls ─────────────────────────────────────────────────────────────────
export const api = {

  // ── Book-Service  BASE: /api/books ──────────────────────────────────────────
  // POST   /api/books/addbook            → adds book, returns saved Book
  // PUT    /api/books/updatebook/{id}    → updates book by ID
  // GET    /api/books/getbyisbn?isbn=    → single book by ISBN
  // GET    /api/books                    → list all books
  // GET    /api/books/findbyauthor/{a}   → list books by author
  // GET    /api/books/totalbooks         → Long count
  // DELETE /api/books/deletebook/{isbn}  → deletes book
  // PUT    /api/books/{title}/copies/{n} → update total copies
  // PUT    /api/books/{title}/issue      → decrement copiesAvailable
  // PUT    /api/books/{title}/return     → increment copiesAvailable
  // GET    /api/books/{title}/availability → boolean/string
  addBook:           (body)       => req("POST",   "/api/books/addbook", body),
  updateBook:        (id, body)   => req("PUT",    `/api/books/updatebook/${id}`, body),
  getBookByISBN:     (isbn)       => req("GET",    `/api/books/getbyisbn?isbn=${isbn}`),
  getAllBooks:        ()           => req("GET",    "/api/books"),
  findByAuthor:      (author)     => req("GET",    `/api/books/findbyauthor/${encodeURIComponent(author)}`),
  getTotalBooks:     ()           => req("GET",    "/api/books/totalbooks"),
  deleteBook:        (isbn)       => req("DELETE", `/api/books/deletebook/${isbn}`),
  updateCopies:      (title, n)   => req("PUT",    `/api/books/${encodeURIComponent(title)}/copies/${n}`),
  issueBook:         (title)      => req("PUT",    `/api/books/${encodeURIComponent(title)}/issue`),
  returnBookCopy:    (title)      => req("PUT",    `/api/books/${encodeURIComponent(title)}/return`),
  checkAvailability: (title)      => req("GET",    `/api/books/${encodeURIComponent(title)}/availability`),

  // ── User-Service  BASE: /api/users ──────────────────────────────────────────
  // POST   /api/users/register           → registers user, returns 201 + saved user
  // PUT    /api/users/updateUser/{id}    → updates user
  // GET    /api/users/getbyid/{id}       → single user by ID
  // GET    /api/users                    → list all users
  // GET    /api/users/{id}/checkstatus   → UserRoleStatus object
  // DELETE /api/users/deletebyid/{id}    → deletes user
  registerUser:      (body)       => req("POST",   "/api/users/register", body),
  updateUser:        (id, body)   => req("PUT",    `/api/users/updateUser/${id}`, body),
  getUserById:       (id)         => req("GET",    `/api/users/getbyid/${id}`),
  getAllUsers:        ()           => req("GET",    "/api/users"),
  checkUserStatus:   (id)         => req("GET",    `/api/users/${id}/checkstatus`),
  deleteUser:        (id)         => req("DELETE", `/api/users/deletebyid/${id}`),

  // ── Loan-Service  BASE: /api/loan ───────────────────────────────────────────
  // POST   /api/loan/borrowbook          → creates loan, validates via Feign
  // PUT    /api/loan/returnbook/{loanId} → returns book, updates status
  // GET    /api/loan/{userId}/Loans      → list loans for a user (single or array)
  // GET    /api/loan                     → Long total count
  borrowBook:        (body)       => req("POST",   "/api/loan/borrowbook", body),
  returnBook:        (loanId)     => req("PUT",    `/api/loan/returnbook/${loanId}`),
  getLoansByUser:    (userId)     => req("GET",    `/api/loan/${userId}/Loans`),
  getTotalLoans:     ()           => req("GET",    "/api/loan"),

  // ── Fine-Service  BASE: /api/fines ──────────────────────────────────────────
  // POST   /api/fines/createfine?loanId= → creates fine for overdue loan
  // GET    /api/fines                    → list all fines
  // GET    /api/fines/getallpendingfines → list PENDING fines only
  createFine:        (loanId)     => req("POST",   `/api/fines/createfine?loanId=${loanId}`),
  getAllFines:        ()           => req("GET",    "/api/fines"),
  getPendingFines:   ()           => req("GET",    "/api/fines/getallpendingfines"),
